SELECT occ_title, mean_wage
FROM occupations
WHERE mean_wage = (
  SELECT MAX(mean_wage)
  FROM occupations
);

SELECT occ_title 
FROM occupations 
WHERE mean_wage > (SELECT AVG(pct_50) FROM wage_percentiles);

SELECT COUNT(*) AS total_occupation_count
FROM occupation_region
WHERE region_id = (SELECT region_id FROM regions WHERE region_name = 'Northeast');

SELECT AVG(ei.employment_count) AS average_employment
FROM occupation_industry ei
WHERE ei.occ_id = 0;
